  &lt;span style="color: ${palette[0]}; font-weight: bold;"&gt;${Math.round(menData?.participation_pct)}%&lt;/span&gt;
  und &lt;span style="color: ${palette[0]}; font-weight: bold;"&gt;${menData?.participant_hours.toFixed(1).replace('.', ',')} Stunden&lt;/span&gt;.
  Der Unterschied beträgt ${Math.abs(diffAbs).toFixed(1).replace('.', ',')} Prozentpunkte
  bzw. ${Math.abs(diffRel).toFixed(0)}%.
  ${diffAbs !== 0 ? `${diffAbs &gt; 0 ? 'Frauen' : 'Männer'} üben die Tätigkeit häufiger aus.` : ''}
&lt;/p&gt;`


























































